(function () {
  const reducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)");
  const desktopWidth = window.matchMedia("(min-width: 900px)");
  const timelineWidth = window.matchMedia("(min-width: 1024px)");
  const hasGsap = window.gsap && window.ScrollTrigger;
  let lenis = null;

  if (hasGsap) {
    gsap.registerPlugin(ScrollTrigger);
  }

  function initLenis() {
    if (reducedMotion.matches || !window.Lenis) return;

    lenis = new Lenis({
      lerp: 0.1,
      smoothWheel: true,
    });

    if (hasGsap) {
      lenis.on("scroll", ScrollTrigger.update);
      gsap.ticker.add((time) => {
        lenis.raf(time * 1000);
      });
      gsap.ticker.lagSmoothing(0);
      return;
    }

    function raf(time) {
      lenis.raf(time);
      requestAnimationFrame(raf);
    }

    requestAnimationFrame(raf);
  }

  function initMagnetic() {
    const targets = document.querySelectorAll("[data-magnetic]");
    if (!targets.length || reducedMotion.matches) return;

    targets.forEach((target) => {
      target.addEventListener("pointermove", (event) => {
        const rect = target.getBoundingClientRect();
        const x = Math.min(Math.max((event.clientX - rect.left - rect.width / 2) * 0.16, -7), 7);
        const y = Math.min(Math.max((event.clientY - rect.top - rect.height / 2) * 0.18, -7), 7);
        target.style.transform = `translate3d(${x}px, ${y}px, 0)`;
      });

      target.addEventListener("pointerleave", () => {
        target.style.transform = "";
      });
    });
  }

  function initAnchorScroll() {
    document.querySelectorAll('a[href^="#"]').forEach((link) => {
      link.addEventListener("click", (event) => {
        const targetSelector = link.getAttribute("href");
        if (!targetSelector || targetSelector === "#") return;

        const target = document.querySelector(targetSelector);
        if (!target) return;

        event.preventDefault();

        if (lenis && !reducedMotion.matches) {
          lenis.scrollTo(target, { offset: -48 });
          return;
        }

        target.scrollIntoView({
          behavior: reducedMotion.matches ? "auto" : "smooth",
          block: "start",
        });
      });
    });
  }

  function initHero() {
    const hero = document.querySelector("#hero");
    const loader = document.querySelector(".page-loader");
    const loaderMark = document.querySelector(".loader-mark");
    const header = document.querySelector("[data-header]");
    const eyebrow = document.querySelector(".hero-eyebrow");
    const headlineLines = Array.from(document.querySelectorAll(".headline-line"));
    const underline = document.querySelector(".headline-underline");
    const lead = document.querySelector(".hero-lead");
    const ctas = Array.from(document.querySelectorAll(".hero-actions .hero-cta"));
    const statCards = Array.from(document.querySelectorAll(".hero-stats .stat-card"));
    const pills = document.querySelector(".hero-pills");
    const orb = document.querySelector(".hero-orb");
    const cardWrap = document.querySelector(".hero-card-parallax");
    const commandCard = document.querySelector(".command-card");
    const coverage = document.querySelector(".hero-coverage");
    const counters = Array.from(document.querySelectorAll(".hero-stats [data-counter]"));

    if (!hero) return;

    function renderFinalCounters() {
      counters.forEach((counter) => {
        const target = Number(counter.dataset.counter || 0);
        counter.textContent = `${target}+`;
      });
    }

    // --- PURE VANILLA JS COUNTER ANIMATION ---
    // Decoupled from GSAP so it runs completely independently 
    function animateCounters() {
      counters.forEach((counter) => {
        if (counter.dataset.counted === "true") return;
        counter.dataset.counted = "true";

        const target = Number(counter.dataset.counter || 0);
        const duration = 2500; // 2.5s for a smooth, premium feel

        function playCountUp() {
          let startTime = null;
          const step = (currentTime) => {
            if (!startTime) startTime = currentTime;
            const progress = Math.min((currentTime - startTime) / duration, 1);
            
            // Premium smooth easing curve
            const easeOut = 1 - Math.pow(1 - progress, 4);
            const currentNum = Math.floor(easeOut * target);

            counter.textContent = `${currentNum}+`;

            if (progress < 1) {
              requestAnimationFrame(step);
            } else {
              // INFINITE LOOP: Pause for 3 seconds, then restart
              setTimeout(playCountUp, 3000);
            }
          };
          requestAnimationFrame(step);
        }

        playCountUp(); // Start the loop
      });
    }

    function initHeroCounters() {
      const stats = document.querySelector(".hero-stats");
      if (!stats || !counters.length) return;

      if (reducedMotion.matches) {
        renderFinalCounters();
        return;
      }

      // Trigger animation using native IntersectionObserver
      const observer = new IntersectionObserver((entries) => {
        if (entries[0].isIntersecting) {
          animateCounters();
          observer.disconnect();
        }
      }, { threshold: 0.1 });
      
      observer.observe(stats);
    }

    function revealImmediately() {
      loader?.remove();
      header?.classList.add("is-ready");
      headlineLines.forEach((line) => {
        line.style.clipPath = "inset(0% 0 0 0)";
      });
      if (underline) underline.style.transform = "scaleX(1)";
      [
        eyebrow,
        lead,
        pills,
        orb,
        commandCard,
        coverage,
        ...ctas,
        ...statCards,
      ]
        .filter(Boolean)
        .forEach((element) => {
          element.style.opacity = "1";
          element.style.transform = "none";
          element.style.filter = "none";
        });
        
      // FIXED: Call initHeroCounters instead of renderFinalCounters 
      // so the animation still plays even if shouldAnimateHeroIntro = false!
      initHeroCounters();
    }

    // Notice how this was set to false in your original code!
    const shouldAnimateHeroIntro = false; 

    if (!hasGsap || reducedMotion.matches || !shouldAnimateHeroIntro) {
      revealImmediately();
      return;
    }

    if (orb) {
      gsap.to(orb, {
        keyframes: [
          { x: 26, y: -12 },
          { x: 0, y: 20 },
          { x: -26, y: -12 },
          { x: 0, y: 0 },
        ],
        duration: 8,
        ease: "sine.inOut",
        repeat: -1,
      });
    }

    if (cardWrap) {
      gsap.fromTo(
        cardWrap,
        { y: -40 },
        {
          y: 40,
          ease: "none",
          scrollTrigger: {
            trigger: hero,
            start: "top top",
            end: "bottom top",
            scrub: true,
          },
        }
      );
    }

    gsap.set(header, { opacity: 0, y: -8 });
    gsap.set(eyebrow, { opacity: 0, y: 8 });
    gsap.set(headlineLines, { clipPath: "inset(100% 0 0 0)" });
    gsap.set(underline, { scaleX: 0, transformOrigin: "0% 50%" });
    gsap.set(lead, { opacity: 0, y: 12 });
    gsap.set(ctas, { opacity: 0, scale: 0.96 });
    gsap.set(statCards, { opacity: 0, y: 16 });
    gsap.set(pills, { opacity: 0, y: 12 });
    gsap.set(orb, { scale: 0.92 });
    gsap.set(commandCard, { opacity: 0, y: 40 });
    gsap.set(coverage, { opacity: 0, y: 8 });

    const loaderTimeline = gsap.timeline({
      defaults: { ease: "power3.out" },
      onComplete: () => loader?.remove(),
    });

    loaderTimeline
      .to(loaderMark, { opacity: 1, duration: 0.38 })
      .to(loaderMark, { y: -12, duration: 0.28 })
      .to(loader, { opacity: 0, duration: 0.24, ease: "power2.inOut" }, 0.66);

    const master = gsap.timeline({
      delay: 0.9,
      defaults: { ease: "power3.out" },
    });

    master
      .to(
        header,
        {
          opacity: 1,
          y: 0,
          duration: 0.55,
          onStart: () => header?.classList.add("is-ready"),
        },
        0
      )
      .to(eyebrow, { opacity: 1, y: 0, duration: 0.55 }, 0)
      .to(headlineLines, { clipPath: "inset(0% 0 0 0)", duration: 0.9, stagger: 0.12 }, 0)
      .to(lead, { opacity: 1, y: 0, duration: 0.65 }, 0.55)
      .to(ctas, { opacity: 1, scale: 1, duration: 0.5, stagger: 0.06 }, 0.75)
      .to(statCards, { opacity: 1, y: 0, duration: 0.62, stagger: 0.08 }, 0.85)
      .to(pills, { opacity: 1, y: 0, duration: 0.5 }, 1.02)
      .to(underline, { scaleX: 1, duration: 0.7, ease: "power3.out" }, 0.95)
      .to(orb, { scale: 1, duration: 1.4 }, 0.4)
      .to(commandCard, { opacity: 1, y: 0, duration: 0.9 }, 0.4)
      .to(coverage, { opacity: 1, y: 0, duration: 0.55 }, 0.72)
      .call(initHeroCounters, null, 1.2);
  }

  function initFoundationUI() {
    const loader = document.querySelector(".page-loader");
    const header = document.querySelector("[data-header]");
    const progressBar = document.querySelector(".scroll-progress__bar");
    const menuToggle = document.querySelector("[data-menu-toggle]");
    const mobileMenu = document.querySelector("[data-mobile-menu]");
    const navLinks = Array.from(document.querySelectorAll(".desktop-nav a, .mobile-menu__nav a"));
    const sections = navLinks
      .map((link) => {
        const target = document.querySelector(link.getAttribute("href"));
        return target ? { link, target } : null;
      })
      .filter(Boolean);

    function updateScrollProgress() {
      if (!progressBar) return;

      const scrollable = document.documentElement.scrollHeight - window.innerHeight;
      const progress = scrollable > 0 ? window.scrollY / scrollable : 0;
      progressBar.style.width = `${Math.max(0, Math.min(1, progress)) * 100}%`;
    }

    function updateHeader() {
      if (!header) return;
      header.classList.add("is-ready");
      header.classList.toggle("is-scrolled", window.scrollY > 8);
    }

    function closeMenu() {
      if (!menuToggle || !mobileMenu) return;
      document.body.classList.remove("menu-open");
      mobileMenu.classList.remove("is-open");
      mobileMenu.setAttribute("aria-hidden", "true");
      mobileMenu.inert = true;
      menuToggle.setAttribute("aria-expanded", "false");
    }

    if (menuToggle && mobileMenu) {
      menuToggle.addEventListener("click", () => {
        const isOpen = menuToggle.getAttribute("aria-expanded") === "true";
        document.body.classList.toggle("menu-open", !isOpen);
        mobileMenu.classList.toggle("is-open", !isOpen);
        mobileMenu.setAttribute("aria-hidden", String(isOpen));
        mobileMenu.inert = isOpen;
        menuToggle.setAttribute("aria-expanded", String(!isOpen));
      });

      mobileMenu.querySelectorAll("a").forEach((link) => {
        link.addEventListener("click", closeMenu);
      });
    }

    if (sections.length) {
      const observer = new IntersectionObserver(
        (entries) => {
          const visible = entries
            .filter((entry) => entry.isIntersecting)
            .sort((a, b) => b.intersectionRatio - a.intersectionRatio)[0];

          if (!visible) return;

          navLinks.forEach((link) => {
            link.classList.toggle("is-active", link.getAttribute("href") === `#${visible.target.id}`);
          });
        },
        {
          threshold: [0.25, 0.45, 0.65],
          rootMargin: "-22% 0px -52% 0px",
        }
      );

      sections.forEach(({ target }) => observer.observe(target));
    }

    updateHeader();
    updateScrollProgress();
    window.addEventListener("scroll", () => {
      updateHeader();
      updateScrollProgress();
    }, { passive: true });
    window.addEventListener("resize", updateScrollProgress);

    window.setTimeout(() => {
      loader?.classList.add("is-hidden");
    }, 360);
  }

  function initReveal() {
    const revealItems = Array.from(document.querySelectorAll("[data-reveal]"));
    if (!revealItems.length) return;

    if (hasGsap && !reducedMotion.matches) {
      revealItems.forEach((item) => {
        gsap.fromTo(
          item,
          { autoAlpha: 0, y: 30 },
          {
            autoAlpha: 1,
            y: 0,
            duration: 0.85,
            delay: Number(item.dataset.delay || 0) / 1000,
            ease: "power3.out",
            scrollTrigger: {
              trigger: item,
              start: "top 82%",
              once: true,
            },
          }
        );
      });
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          entry.target.classList.remove("is-reveal-pending");
          observer.unobserve(entry.target);
        });
      },
      { threshold: 0.16, rootMargin: "0px 0px -10% 0px" }
    );

    revealItems.forEach((item) => {
      item.classList.add("is-reveal-pending");
      observer.observe(item);
    });
  }

  // --- STANDARD COUNTERS DECOUPLED FROM GSAP ---
  function initCounters() {
    const counters = Array.from(document.querySelectorAll("[data-counter]")).filter(
      (counter) => !counter.closest(".hero-stats")
    );
    if (!counters.length) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          const counter = entry.target;
          if (counter.dataset.counted === "true") return;
          counter.dataset.counted = "true";

          const target = Number(counter.dataset.counter);
          const duration = reducedMotion.matches ? 0 : 2500;

          function playCountUp() {
            let startTime = null;
            const step = (currentTime) => {
              if (!startTime) startTime = currentTime;
              const progress = duration ? Math.min((currentTime - startTime) / duration, 1) : 1;
              
              const easeOut = 1 - Math.pow(1 - progress, 4);
              const currentNum = Math.floor(easeOut * target);

              counter.textContent = `${currentNum}+`;

              if (progress < 1) {
                requestAnimationFrame(step);
              } else {
                // Endless Loop!
                setTimeout(playCountUp, 3000);
              }
            };
            requestAnimationFrame(step);
          }

          playCountUp();
          observer.unobserve(counter); // Stops watching once it starts
        });
      },
      { threshold: 0.5 }
    );

    counters.forEach((counter) => observer.observe(counter));
  }

  function initProcessTimeline() {
    const timeline = document.querySelector("[data-process-timeline]");
    if (!timeline) return;

    const steps = Array.from(timeline.querySelectorAll("[data-process-step]"));
    const nodes = Array.from(timeline.querySelectorAll("[data-step-node]"));
    const railFill = timeline.querySelector(".process-rail-fill");
    let activeIndex = -1;

    function setActive(index) {
      if (index === activeIndex || index < 0) return;
      activeIndex = index;

      nodes.forEach((node, nodeIndex) => {
        node.classList.toggle("is-active", nodeIndex === index);
        node.classList.toggle("is-complete", nodeIndex < index);
      });
      
      // Also highlight the corresponding card for icon/title animations
      steps.forEach((step, stepIndex) => {
        step.classList.toggle("is-active", stepIndex === index);
      });
    }

    if (!steps.length) return;

    if (hasGsap && !reducedMotion.matches && timelineWidth.matches) {
      gsap.set(railFill, { scaleY: 0, transformOrigin: "top center" });

      steps.forEach((step, index) => {
        ScrollTrigger.create({
          trigger: step,
          start: "top center",
          end: "bottom center",
          onEnter: () => setActive(index),
          onEnterBack: () => setActive(index),
        });
      });

      // Fixed Progress logic: Ensures self.progress hits 1.0 when Step 5 is reached
      ScrollTrigger.create({
        trigger: timeline,
        start: "top center", 
        end: "bottom center",
        scrub: true,
        onUpdate: (self) => {
           gsap.set(railFill, { scaleY: self.progress });
        }
      });
    }
  }

  function initPresenceMap() {
    const card = document.querySelector("[data-presence-map]");
    if (!card || card.dataset.rendered === "true") return;

    const dotsGroup = card.querySelector("[data-map-dots]");
    const arcsGroup = card.querySelector("[data-map-arcs]");
    const citiesGroup = card.querySelector("[data-map-cities]");
    if (!dotsGroup || !arcsGroup || !citiesGroup) return;

    card.dataset.rendered = "true";

    const svgNs = "http://www.w3.org/2000/svg";
    const width = 900;
    const height = 560;
    const maxLat = 82;
    const mercatorLimit = Math.log(Math.tan(Math.PI / 4 + (maxLat * Math.PI) / 360));

    const landForms = [
      { lng: -103, lat: 50, rx: 58, ry: 23, tilt: -14 },
      { lng: -78, lat: 33, rx: 27, ry: 16, tilt: -26 },
      { lng: -43, lat: -14, rx: 22, ry: 36, tilt: -12 },
      { lng: -68, lat: -30, rx: 14, ry: 29, tilt: 8 },
      { lng: -42, lat: 72, rx: 22, ry: 10, tilt: -10 },
      { lng: 16, lat: 49, rx: 29, ry: 14, tilt: 4 },
      { lng: 20, lat: 6, rx: 27, ry: 37, tilt: -5 },
      { lng: 44, lat: 24, rx: 19, ry: 14, tilt: 12 },
      { lng: 76, lat: 20, rx: 16, ry: 18, tilt: -8 },
      { lng: 89, lat: 47, rx: 63, ry: 24, tilt: 0 },
      { lng: 113, lat: 25, rx: 35, ry: 19, tilt: -8 },
      { lng: 104, lat: 4, rx: 22, ry: 13, tilt: 4 },
      { lng: 137, lat: 37, rx: 11, ry: 17, tilt: 18 },
      { lng: 134, lat: -25, rx: 22, ry: 17, tilt: 8 },
      { lng: 145, lat: -6, rx: 16, ry: 9, tilt: 8 },
      { lng: 174, lat: -41, rx: 7, ry: 9, tilt: 15 },
    ];

    const cities = [
      { name: "Dubai", lat: 25.2048, lng: 55.2708, origin: true },
      { name: "Abu Dhabi", lat: 24.4539, lng: 54.3773 },
      { name: "Riyadh", lat: 24.7136, lng: 46.6753 },
      { name: "Mumbai", lat: 19.076, lng: 72.8777 },
      { name: "Bangalore", lat: 12.9716, lng: 77.5946 },
      { name: "London", lat: 51.5072, lng: -0.1276 },
      { name: "New York", lat: 40.7128, lng: -74.006 },
      { name: "Singapore", lat: 1.3521, lng: 103.8198 },
    ];

    function createSvgElement(tag, attributes) {
      const element = document.createElementNS(svgNs, tag);
      Object.entries(attributes).forEach(([key, value]) => {
        element.setAttribute(key, value);
      });
      return element;
    }

    function project(lng, lat) {
      const clampedLat = Math.max(-maxLat, Math.min(maxLat, lat));
      const mercatorY = Math.log(Math.tan(Math.PI / 4 + (clampedLat * Math.PI) / 360));

      return {
        x: ((lng + 180) / 360) * width,
        y: (1 - (mercatorY + mercatorLimit) / (2 * mercatorLimit)) * height,
      };
    }

    function isInsideForm(lng, lat, form) {
      const rotation = (-form.tilt * Math.PI) / 180;
      const dx = lng - form.lng;
      const dy = lat - form.lat;
      const x = dx * Math.cos(rotation) - dy * Math.sin(rotation);
      const y = dx * Math.sin(rotation) + dy * Math.cos(rotation);
      return (x * x) / (form.rx * form.rx) + (y * y) / (form.ry * form.ry) <= 1;
    }

    function isLand(lng, lat) {
      return landForms.some((form) => isInsideForm(lng, lat, form));
    }

    const dotsFragment = document.createDocumentFragment();
    const spacing = 2.65;
    let row = 0;

    for (let lat = -55; lat <= 78; lat += spacing) {
      const rowOffset = row % 2 === 0 ? 0 : spacing / 2;

      for (let lng = -178 + rowOffset; lng <= 178; lng += spacing) {
        if (!isLand(lng, lat)) continue;

        const point = project(lng, lat);
        const dot = createSvgElement("circle", {
          class: "world-dot",
          cx: point.x.toFixed(2),
          cy: point.y.toFixed(2),
          r: "1.15",
        });

        dot.dataset.x = point.x.toFixed(2);
        dot.dataset.y = point.y.toFixed(2);
        dotsFragment.appendChild(dot);
      }

      row += 1;
    }

    dotsGroup.appendChild(dotsFragment);

    const projectedCities = cities.map((city) => ({
      ...city,
      point: project(city.lng, city.lat),
    }));
    const origin = projectedCities.find((city) => city.origin);

    projectedCities.forEach((city) => {
      if (!city.origin && origin) {
        const dx = city.point.x - origin.point.x;
        const dy = city.point.y - origin.point.y;
        const distance = Math.hypot(dx, dy) || 1;
        const normalX = -dy / distance;
        const normalY = dx / distance;
        const direction = city.point.x < origin.point.x ? -1 : 1;
        const curve = Math.max(24, Math.min(130, distance * 0.2));
        const controlX = (origin.point.x + city.point.x) / 2 + normalX * curve * direction;
        const controlY = (origin.point.y + city.point.y) / 2 + normalY * curve * direction - Math.min(54, distance * 0.06);
        const path = createSvgElement("path", {
          class: "world-arc",
          d: `M ${origin.point.x.toFixed(2)} ${origin.point.y.toFixed(2)} Q ${controlX.toFixed(2)} ${controlY.toFixed(2)} ${city.point.x.toFixed(2)} ${city.point.y.toFixed(2)}`,
          pathLength: "1",
        });

        arcsGroup.appendChild(path);
      }

      const marker = createSvgElement("g", {
        class: "world-city",
        transform: `translate(${city.point.x.toFixed(2)} ${city.point.y.toFixed(2)})`,
      });
      const title = createSvgElement("title", {});
      const pulse = createSvgElement("circle", {
        class: "world-city-pulse",
        r: "7",
      });
      const core = createSvgElement("circle", {
        class: "world-city-core",
        r: city.origin ? "4.8" : "3.8",
      });

      title.textContent = city.name;
      marker.append(title, pulse, core);
      citiesGroup.appendChild(marker);
    });

    const dots = Array.from(dotsGroup.querySelectorAll(".world-dot")).sort((a, b) => {
      const xDiff = Number(a.dataset.x) - Number(b.dataset.x);
      return xDiff || Number(a.dataset.y) - Number(b.dataset.y);
    });
    const arcs = Array.from(arcsGroup.querySelectorAll(".world-arc"));
    const pulses = Array.from(citiesGroup.querySelectorAll(".world-city-pulse"));
    const regionCards = Array.from(document.querySelectorAll("[data-presence-card]"));

    if (hasGsap && !reducedMotion.matches) {
      gsap.set(dots, { autoAlpha: 0 });
      gsap.set(arcs, { strokeDashoffset: 1 });

      gsap.to(dots, {
        autoAlpha: 1,
        duration: 0.55,
        ease: "power1.out",
        stagger: 0.001,
        scrollTrigger: {
          trigger: card,
          start: "top 78%",
          once: true,
        },
      });

      gsap.to(arcs, {
        strokeDashoffset: 0,
        ease: "none",
        stagger: 0.08,
        scrollTrigger: {
          trigger: card,
          start: "top 78%",
          end: "bottom 42%",
          scrub: true,
        },
      });

      gsap.fromTo(
        pulses,
        { scale: 1, autoAlpha: 1 },
        {
          scale: 1.6,
          autoAlpha: 0,
          duration: 1.6,
          ease: "power2.out",
          repeat: -1,
          stagger: 0.4,
        }
      );

      if (regionCards.length) {
        gsap.fromTo(
          regionCards,
          { autoAlpha: 0, y: 18 },
          {
            autoAlpha: 1,
            y: 0,
            duration: 0.6,
            ease: "power3.out",
            stagger: 0.08,
            scrollTrigger: {
              trigger: ".region-columns",
              start: "top 86%",
              once: true,
            },
          }
        );
      }

      return;
    }

    dots.forEach((dot) => {
      dot.style.opacity = "1";
    });
    arcs.forEach((arc) => {
      arc.style.strokeDashoffset = "0";
    });
    pulses.forEach((pulse) => {
      pulse.style.opacity = "0.22";
    });
  }

  function clamp(value, min, max) {
    return Math.min(Math.max(value, min), max);
  }

  function initScrollProgress() {
    const progress = document.querySelector(".scroll-progress__bar");
    if (!progress) return;

    function updateProgress() {
      const scrollable = document.documentElement.scrollHeight - window.innerHeight;
      const amount = scrollable > 0 ? window.scrollY / scrollable : 0;
      progress.style.width = `${amount * 100}%`;
    }

    updateProgress();
    window.addEventListener("scroll", updateProgress, { passive: true });
    window.addEventListener("resize", updateProgress);
  }

  function initAboutMotion() {
    const story = document.querySelector("[data-about-parallax]");
    const valueCards = Array.from(document.querySelectorAll("[data-about-value]"));
    if (reducedMotion.matches || (!story && !valueCards.length)) return;

    if (hasGsap) {
      if (story) {
        gsap.fromTo(
          story,
          { "--about-parallax-y": "30px" },
          {
            "--about-parallax-y": "-30px",
            ease: "none",
            scrollTrigger: {
              trigger: story,
              start: "top bottom",
              end: "bottom top",
              scrub: true,
            },
          }
        );
      }

      if (valueCards.length) {
        const valueInners = valueCards
          .map((card) => card.querySelector(".value-card__inner"))
          .filter(Boolean);
        const valueIcons = valueCards
          .map((card) => card.querySelector(".value-icon"))
          .filter(Boolean);

        gsap.fromTo(
          valueInners,
          { y: 12, autoAlpha: 0.84 },
          {
            y: 0,
            autoAlpha: 1,
            ease: "none",
            stagger: 0.08,
            scrollTrigger: {
              trigger: ".values-strip",
              start: "top 88%",
              end: "bottom 72%",
              scrub: 0.4,
            },
          }
        );

        gsap.fromTo(
          valueIcons,
          { scale: 0.85, autoAlpha: 0 },
          {
            scale: 1,
            autoAlpha: 1,
            ease: "none",
            stagger: 0.08,
            scrollTrigger: {
              trigger: ".values-strip",
              start: "top 86%",
              end: "bottom 74%",
              scrub: 0.4,
            },
          }
        );
      }

      return;
    }

    let ticking = false;

    function updateAboutMotion() {
      ticking = false;
      const viewportHeight = window.innerHeight || 1;

      if (story) {
        const rect = story.getBoundingClientRect();
        const progress = clamp((viewportHeight - rect.top) / (viewportHeight + rect.height), 0, 1);
        const y = 30 - progress * 60;
        story.style.setProperty("--about-parallax-y", `${y.toFixed(2)}px`);
      }

      valueCards.forEach((card, index) => {
        const rect = card.getBoundingClientRect();
        const progress = clamp((viewportHeight * 0.88 - rect.top + index * 18) / (viewportHeight * 0.34), 0, 1);
        const icon = card.querySelector(".value-icon");
        const inner = card.querySelector(".value-card__inner");

        inner?.style.setProperty("--value-y", `${(1 - progress) * 12}px`);
        inner?.style.setProperty("--value-opacity", `${0.84 + progress * 0.16}`);
        icon?.style.setProperty("--about-icon-scale", `${0.85 + progress * 0.15}`);
        icon?.style.setProperty("--about-icon-opacity", `${progress}`);
      });
    }

    function requestUpdate() {
      if (ticking) return;
      ticking = true;
      requestAnimationFrame(updateAboutMotion);
    }

    updateAboutMotion();
    window.addEventListener("scroll", requestUpdate, { passive: true });
    window.addEventListener("resize", requestUpdate);
  }

  function initTilt() {
    const tiltCards = document.querySelectorAll("[data-tilt]");

    tiltCards.forEach((card) => {
      let frame = 0;

      function updateTilt(event) {
        if (reducedMotion.matches || desktopWidth.matches === false) return;

        const rect = card.getBoundingClientRect();
        const x = event.clientX - rect.left;
        const y = event.clientY - rect.top;
        const rx = ((y / rect.height) - 0.5) * -6;
        const ry = ((x / rect.width) - 0.5) * 6;

        cancelAnimationFrame(frame);
        frame = requestAnimationFrame(() => {
          card.style.setProperty("--mx", `${x}px`);
          card.style.setProperty("--my", `${y}px`);
          card.style.transform = `perspective(1000px) rotateX(${rx}deg) rotateY(${ry}deg) translateY(-4px)`;
        });
      }

      card.addEventListener("pointerenter", () => {
        if (reducedMotion.matches || desktopWidth.matches === false) return;
        card.classList.add("tilt-active");
      });

      card.addEventListener("pointermove", updateTilt);

      card.addEventListener("pointerleave", () => {
        cancelAnimationFrame(frame);
        card.classList.remove("tilt-active");
        card.style.transform = "";
      });
    });
  }

  function initServiceReveal() {
    const cards = document.querySelectorAll(".service-card");
    if (!cards.length || reducedMotion.matches) return;

    if (hasGsap) {
      gsap.fromTo(
        cards,
        { autoAlpha: 0, y: 34 },
        {
          autoAlpha: 1,
          y: 0,
          duration: 0.7,
          ease: "power3.out",
          stagger: 0.12,
          scrollTrigger: {
            trigger: ".service-grid",
            start: "top 78%",
            once: true,
          },
        }
      );
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          entry.target.animate(
            [
              { opacity: 0, transform: "translateY(34px)" },
              { opacity: 1, transform: "translateY(0)" },
            ],
            { duration: 700, easing: "cubic-bezier(.22,1,.36,1)", fill: "both" }
          );
          observer.unobserve(entry.target);
        });
      },
      { threshold: 0.18 }
    );

    cards.forEach((card) => observer.observe(card));
  }

  function initProductShowcase() {
    const pin = document.querySelector("[data-product-pin]");
    const stage = document.querySelector("[data-product-stage]");
    const track = document.querySelector("[data-product-track]");
    const cards = Array.from(document.querySelectorAll("[data-product-card]"));
    const dots = Array.from(document.querySelectorAll("[data-product-dot]"));
    const fill = document.querySelector("[data-progress-fill]");
    let horizontalTrigger = null;
    let horizontalTween = null;
    let activeIndex = -1;

    if (!pin || !stage || !track || !cards.length) return;

    function setActive(index) {
      if (index === activeIndex || index < 0) return;
      activeIndex = index;

      cards.forEach((card, cardIndex) => {
        card.classList.toggle("is-active", cardIndex === index);
      });

      dots.forEach((dot, dotIndex) => {
        dot.classList.toggle("is-active", dotIndex === index);
      });
    }

    function markCenteredCard() {
      const viewportCenter = window.innerWidth / 2;
      let closestIndex = 0;
      let closestDistance = Number.POSITIVE_INFINITY;

      cards.forEach((card, index) => {
        const rect = card.getBoundingClientRect();
        const cardCenter = rect.left + rect.width / 2;
        const distance = Math.abs(cardCenter - viewportCenter);

        if (distance < closestDistance) {
          closestDistance = distance;
          closestIndex = index;
        }
      });

      setActive(closestIndex);
    }

    function setProgress(progress) {
      if (fill) {
        fill.style.transform = `scaleX(${Math.max(0, Math.min(1, progress))})`;
      }
    }

    function destroyHorizontal() {
      if (horizontalTrigger) {
        horizontalTrigger.kill();
        horizontalTrigger = null;
      }

      if (horizontalTween) {
        horizontalTween.kill();
        horizontalTween = null;
      }

      track.classList.remove("is-pinning");
      if (hasGsap) {
        gsap.set(track, { clearProps: "transform,willChange" });
      }
      setProgress(0);
      setActive(0);
    }

    function enableHorizontal() {
      if (!hasGsap || reducedMotion.matches || desktopWidth.matches === false) {
        destroyHorizontal();
        return;
      }

      destroyHorizontal();

      horizontalTween = gsap.to(track, {
        xPercent: () => -((track.scrollWidth - window.innerWidth) / track.scrollWidth) * 100,
        ease: "none",
        paused: true,
      });

      horizontalTrigger = ScrollTrigger.create({
        trigger: pin,
        start: "top top",
        end: () => `+=${Math.max(pin.offsetHeight - window.innerHeight, window.innerHeight)}`,
        pin: stage,
        scrub: 0.6,
        animation: horizontalTween,
        invalidateOnRefresh: true,
        anticipatePin: 1,
        onEnter: () => track.classList.add("is-pinning"),
        onEnterBack: () => track.classList.add("is-pinning"),
        onLeave: () => track.classList.remove("is-pinning"),
        onLeaveBack: () => track.classList.remove("is-pinning"),
        onRefresh: (self) => {
          setProgress(self.progress);
          markCenteredCard();
        },
        onUpdate: (self) => {
          setProgress(self.progress);
          markCenteredCard();
        },
      });

      requestAnimationFrame(() => {
        ScrollTrigger.refresh();
        markCenteredCard();
      });
    }

    dots.forEach((dot, index) => {
      dot.addEventListener("click", () => {
        if (!horizontalTrigger || desktopWidth.matches === false || reducedMotion.matches) {
          cards[index].scrollIntoView({ behavior: reducedMotion.matches ? "auto" : "smooth", block: "center" });
          setActive(index);
          return;
        }

        const distance = horizontalTrigger.end - horizontalTrigger.start;
        const progress = cards.length > 1 ? index / (cards.length - 1) : 0;
        window.scrollTo({
          top: horizontalTrigger.start + distance * progress,
          behavior: "smooth",
        });
      });
    });

    reducedMotion.addEventListener("change", enableHorizontal);
    desktopWidth.addEventListener("change", enableHorizontal);
    window.addEventListener("resize", () => {
      if (desktopWidth.matches && !reducedMotion.matches && window.ScrollTrigger) {
        ScrollTrigger.refresh();
      }
      markCenteredCard();
    });

    enableHorizontal();
  }

  function initLazyPresenceMap() {
    const card = document.querySelector("[data-presence-map]");
    if (!card) return;

    if (!("IntersectionObserver" in window)) {
      initPresenceMap();
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          initPresenceMap();
          observer.disconnect();
        });
      },
      { threshold: 0.18, rootMargin: "120px 0px" }
    );

    observer.observe(card);
  }

  function initContactForm() {
  const form = document.getElementById("brief-form");
  const status = document.getElementById("form-status");
  const submitBtn = document.getElementById("submit-btn");

  if (!form) return;

  form.addEventListener("submit", (event) => {
    event.preventDefault();

    // Show loading state
    status.textContent = "Sending your brief...";
    status.style.color = "#0071e3";
    submitBtn.style.opacity = "0.5";
    submitBtn.style.pointerEvents = "none";

    const formData = new FormData(form);
    const object = Object.fromEntries(formData);
    const json = JSON.stringify(object);

    fetch("https://api.web3forms.com/submit", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Accept: "application/json",
      },
      body: json,
    })
      .then(async (response) => {
        let res = await response.json();
        if (response.status == 200) {
          status.textContent = "Success! We have received your brief.";
          status.style.color = "#28a745"; // Green for success
          form.reset();
        } else {
          status.textContent = res.message;
          status.style.color = "#dc3545"; // Red for error
        }
      })
      .catch((error) => {
        status.textContent = "Something went wrong. Please try again.";
        status.style.color = "#dc3545";
      })
      .then(() => {
        submitBtn.style.opacity = "1";
        submitBtn.style.pointerEvents = "auto";
        setTimeout(() => {
          status.textContent = "";
        }, 5000);
      });
  });
}

if (history.scrollRestoration) { history.scrollRestoration = 'manual'; }
window.scrollTo(0, 0);

// Fix for Process Rail Logic
function syncProcessRail() {
    const rail = document.querySelector(".process-rail-fill");
    const timeline = document.querySelector(".process-timeline");
    
    if (rail && timeline) {
        window.addEventListener("scroll", () => {
            const rect = timeline.getBoundingClientRect();
            const winH = window.innerHeight;
            // Calculate progress based on container center
            let progress = (winH/2 - rect.top) / rect.height;
            progress = Math.max(0, Math.min(1, progress));
            rail.style.transform = `translateX(-50%) scaleY(${progress})`;
        });
    }
}
syncProcessRail();

  function initChatDock() {
    const dock = document.querySelector(".chat-dock");
    const hero = document.getElementById("hero");
    const contact = document.getElementById("contact");
    const mobileView = window.matchMedia("(max-width: 760px)");
    if (!dock || !hero) return;

    const updateVisibility = () => {
      const heroBottom = hero.offsetTop + hero.offsetHeight * 0.72;
      dock.classList.toggle("is-visible", window.scrollY > heroBottom);
    };

    updateVisibility();
    window.addEventListener("scroll", updateVisibility, { passive: true });
    window.addEventListener("resize", updateVisibility);

    if (contact && "IntersectionObserver" in window) {
      const contactObserver = new IntersectionObserver(
        (entries) => {
          const isContactVisible = entries.some((entry) => entry.isIntersecting);
          dock.classList.toggle("is-contact-visible", mobileView.matches && isContactVisible);
        },
        { threshold: 0.12 }
      );

      contactObserver.observe(contact);
      mobileView.addEventListener("change", () => {
        if (!mobileView.matches) {
          dock.classList.remove("is-contact-visible");
        }
      });
    }
  }
  function revealVisibleItems() {
    const visibleItems = document.querySelectorAll('[data-reveal]');
    visibleItems.forEach((item) => {
      const rect = item.getBoundingClientRect();
      if (rect.top < window.innerHeight * 0.96 && rect.bottom > 0) {
        if (hasGsap) {
          gsap.set(item, { autoAlpha: 1, y: 0, filter: 'blur(0px)' });
        } else {
          item.style.opacity = '1';
          item.style.visibility = 'visible';
          item.style.transform = 'none';
          item.style.filter = 'none';
        }
      }
    });
  }

  function initInitialHashScroll() {
    if (!window.location.hash) return;
    const target = document.querySelector(window.location.hash);
    if (!target) return;

    window.setTimeout(() => {
      target.scrollIntoView({ block: 'start' });
      if (window.ScrollTrigger) {
        ScrollTrigger.refresh();
      }
      revealVisibleItems();
    }, 700);
  }

  function init() {
    initLenis();
    initFoundationUI();
    initHero();
    initAnchorScroll();
    initMagnetic();
    initReveal();
    initCounters();
    initTilt();
    initAboutMotion();
    initServiceReveal();
    initProductShowcase();
    initInitialHashScroll();
    window.setTimeout(revealVisibleItems, 900);
    initProcessTimeline();
    initLazyPresenceMap();
    initContactForm();
    initChatDock();
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init, { once: true });
  } else {
    init();
  }
})();